sp_widget.client_script:
api.controller=function($scope,spUtil) {
  /* widget controller */
  var c = this;
	c.openMap=false;

	c.openMap = false;

    $scope.$on('openmappings', function(event, data) {

        c.openMap = true;
				//spUtil.addInfoMessage("fi "+data.filter)
        spUtil.get('incentnow-table-widget', {
            table: 'x_ctans_incentnow_metadata_mapping',
            view: 'portal_view',
            viewperiod: 'false',
            filter: data.filter
        }).then(function(response) {
            c.data.dataMappingList = response;

					setTimeout(function() {
						var el = document.getElementById("mappingTable");
						if (el) {
							el.scrollIntoView({ behavior: "smooth", block: "start" });
						}
					}, 100);


        });
    });

	c.goBack = function() {
        window.history.back();
    };


};

sp_widget.css:
.admin-page-topbar-title {
  font-size: 22px;
  font-weight: 800;
  color: #0f172a;
  flex: 1;
}



.admin-page-header p {
  margin: 4px 0 0;
  color: #6b7280;
}

.admin-page-topbar {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #e2e8f0;
}

.admin-back-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #ffffff;
  border: 1.5px solid #e2e8f0;
  cursor: pointer;
  color: #374151;
  flex-shrink: 0;
  transition: background 0.15s, border-color 0.15s;
}

.admin-back-btn:hover {
  background: #f1f5f9;
  border-color: #94a3b8;
}

